-- ============================================================================
-- IP validation: reject private, loopback, link-local, multicast ranges
-- ============================================================================

local function ip_octets(ip_str)
    local o1, o2, o3, o4 = ip_str:match("^(%d+)%.(%d+)%.(%d+)%.(%d+)$")
    if not o1 then
        return nil
    end
    o1, o2, o3, o4 = tonumber(o1), tonumber(o2), tonumber(o3), tonumber(o4)
    if o1 > 255 or o2 > 255 or o3 > 255 or o4 > 255 then
        return nil
    end
    return o1, o2, o3, o4
end

local function is_ipv6_loopback_or_private(ip_str)
    -- Basic checks for IPv6 dangerous addresses
    local lower = ip_str:lower()
    if lower == "::1" or lower == "::ffff:127.0.0.1" then
        return true
    end
    -- Link-local fe80::/10
    if lower:match("^fe[89ab]") then
        return true
    end
    -- Unique local fc00::/7
    if lower:match("^f[cd]") then
        return true
    end
    -- IPv4-mapped IPv6 addresses ::ffff:x.x.x.x - extract and check IPv4 part
    local mapped = lower:match("^::ffff:(%d+%.%d+%.%d+%.%d+)$")
    if mapped then
        local o1, o2, o3, o4 = ip_octets(mapped)
        if o1 then
            return is_private_ipv4(o1, o2, o3, o4)
        end
    end
    return false
end

local function is_private_ipv4(o1, o2, o3, o4)
    -- Loopback: 127.0.0.0/8
    if o1 == 127 then
        return true
    end
    -- 0.0.0.0/8 (current network)
    if o1 == 0 then
        return true
    end
    -- Private 10.0.0.0/8
    if o1 == 10 then
        return true
    end
    -- Private 172.16.0.0/12
    if o1 == 172 and o2 >= 16 and o2 <= 31 then
        return true
    end
    -- Private 192.168.0.0/16
    if o1 == 192 and o2 == 168 then
        return true
    end
    -- Link-local 169.254.0.0/16 (includes cloud metadata 169.254.169.254)
    if o1 == 169 and o2 == 254 then
        return true
    end
    -- Multicast 224.0.0.0/4
    if o1 >= 224 and o1 <= 239 then
        return true
    end
    -- Broadcast / reserved 240.0.0.0/4
    if o1 >= 240 then
        return true
    end
    -- 100.64.0.0/10 (Carrier-grade NAT)
    if o1 == 100 and o2 >= 64 and o2 <= 127 then
        return true
    end
    -- 192.0.0.0/24 (IETF protocol assignments)
    if o1 == 192 and o2 == 0 and o3 == 0 then
        return true
    end
    -- 192.0.2.0/24, 198.51.100.0/24, 203.0.113.0/24 (documentation)
    if o1 == 192 and o2 == 0 and o3 == 2 then
        return true
    end
    if o1 == 198 and o2 == 51 and o3 == 100 then
        return true
    end
    if o1 == 203 and o2 == 0 and o3 == 113 then
        return true
    end
    -- 198.18.0.0/15 (benchmarking)
    if o1 == 198 and (o2 == 18 or o2 == 19) then
        return true
    end
    return false
end

local function is_dangerous_ip(ip_str)
    if not ip_str or ip_str == "" then
        return true, "empty IP"
    end

    -- Check IPv4
    local o1, o2, o3, o4 = ip_octets(ip_str)
    if o1 then
        if is_private_ipv4(o1, o2, o3, o4) then
            return true, "private/reserved IPv4 address: " .. ip_str
        end
        return false
    end

    -- Check IPv6
    if ip_str:find(":") then
        if is_ipv6_loopback_or_private(ip_str) then
            return true, "private/reserved IPv6 address: " .. ip_str
        end
        return false
    end

    return true, "unrecognized IP format: " .. ip_str
end

-- ============================================================================
-- DNS resolution with safety checks
-- ============================================================================

local function resolve_and_validate(hostname)
    -- If the hostname itself looks like an IP, validate directly
    local o1 = ip_octets(hostname)
    if o1 then
        local dangerous, reason = is_dangerous_ip(hostname)
        if dangerous then
            return nil, reason
        end
        return hostname
    end

    local r, err = resolver:new({
        nameservers = DNS_SERVERS,
        retrans = 2,
        timeout = DNS_TIMEOUT,
    })
    if not r then
        return nil, "failed to create DNS resolver: " .. (err or "unknown")
    end

    local answers, err = r:query(hostname, { qtype = 1 })  -- A record
    if not answers then
        return nil, "DNS resolution failed for " .. hostname .. ": " .. (err or "unknown")
    end

    if answers.errcode then
        return nil, "DNS error for " .. hostname .. ": " .. (answers.errstr or "unknown")
    end

    -- Validate ALL resolved IPs, not just the first one
    local safe_ip = nil
    for _, ans in ipairs(answers) do
        if ans.address then
            local dangerous, reason = is_dangerous_ip(ans.address)
            if dangerous then
                return nil, "DNS for " .. hostname .. " resolved to dangerous address: " .. reason
            end
            if not safe_ip then
                safe_ip = ans.address
            end
        end
    end

    -- Also check AAAA records
    local answers_v6, err_v6 = r:query(hostname, { qtype = 28 })  -- AAAA record
    if answers_v6 and not answers_v6.errcode then
        for _, ans in ipairs(answers_v6) do
            if ans.address then
                local dangerous, reason = is_dangerous_ip(ans.address)
                if dangerous then
                    return nil, "DNS for " .. hostname .. " resolved to dangerous IPv6 address: " .. reason
                end
            end
        end
    end

    if not safe_ip then
        return nil, "no valid A record found for " .. hostname
    end

    return safe_ip
end

-- ============================================================================
-- URL parsing and validation
-- ============================================================================

local function parse_url(url)
    if not url or url == "" then
        return nil, "empty URL"
    end

    -- Only allow http and https schemes
    local scheme, rest = url:match("^(https?)://(.+)$")
    if not scheme then
        return nil, "only http and https schemes are allowed"
    end

    -- Extract host (and optional port) from the rest
    local host_port, path = rest:match("^([^/]+)(/.*)$")
    if not host_port then
        host_port = rest
        path = "/"
    end

    local host, port = host_port:match("^(.+):(%d+)$")
    if not host then
        host = host_port
        port = (scheme == "https") and 443 or 80
    else
        port = tonumber(port)
    end

    -- Remove any userinfo (user:pass@) - reject these outright
    if host:find("@") then
        return nil, "URLs with userinfo are not allowed"
    end

    -- Normalize host to lowercase
    host = host:lower()

    -- Strip trailing dot from FQDN
    if host:sub(-1) == "." then
        host = host:sub(1, -2)
    end

    return {
        scheme = scheme,
        host = host,
        port = port,
        path = path,
        url = url,
    }
end

local function validate_url(url_str)
    local parsed, err = parse_url(url_str)
    if not parsed then
        return nil, err
    end

    -- Check against allowlist
    if not ALLOWED_HOSTS[parsed.host] then
        return nil, "host '" .. parsed.host .. "' is not in the allowlist"
    end

    -- Only allow standard ports
    if parsed.scheme == "https" and parsed.port ~= 443 then
        return nil, "non-standard HTTPS port " .. parsed.port .. " is not allowed"
    end
    if parsed.scheme == "http" and parsed.port ~= 80 then
        return nil, "non-standard HTTP port " .. parsed.port .. " is not allowed"
    end

    -- Resolve DNS and validate all resulting IPs
    local resolved_ip, resolve_err = resolve_and_validate(parsed.host)
    if not resolved_ip then
        return nil, resolve_err
    end

    parsed.resolved_ip = resolved_ip
    return parsed
end

