local function handle_request()
    -- Only allow POST for webhook forwarding
    if ngx.req.get_method() ~= "POST" then
        ngx.status = 405
        ngx.header["Content-Type"] = "application/json"
        ngx.say('{"error":"method not allowed, use POST"}')
        return ngx.exit(405)
    end

    -- Get and validate the target URL
    local target_url = ngx.var.arg_url
    if not target_url then
        ngx.status = 400
        ngx.header["Content-Type"] = "application/json"
        ngx.say('{"error":"missing required query parameter: url"}')
        return ngx.exit(400)
    end

    -- URL-decode the parameter
    target_url = ngx.unescape_uri(target_url)

    -- Validate the URL: allowlist check, DNS resolution, IP safety
    local parsed, err = validate_url(target_url)
    if not parsed then
        ngx.log(ngx.WARN, "SSRF protection blocked request to: ", target_url, " reason: ", err)
        ngx.status = 403
        ngx.header["Content-Type"] = "application/json"
        ngx.say('{"error":"forbidden destination","detail":"' .. err .. '"}')
        return ngx.exit(403)
    end

    -- Read the incoming request body to forward
    ngx.req.read_body()
    local req_body = ngx.req.get_body_data()

    -- Get content-type from the incoming request to forward
    local content_type = ngx.req.get_headers()["Content-Type"] or "application/json"

    -- Create HTTP client
    local httpc = http.new()
    httpc:set_timeout(REQUEST_TIMEOUT)

    -- Make the outbound request
    -- We disable redirects entirely (safest) or handle them manually with revalidation
    local res, req_err

    if MAX_REDIRECTS == 0 then
        -- No redirects allowed - safest option
        res, req_err = httpc:request_uri(target_url, {
            method = "POST",
            body = req_body,
            headers = {
                ["Content-Type"] = content_type,
                ["User-Agent"] = "WebhookForwarder/1.0",
                ["Host"] = parsed.host,
            },
            ssl_verify = true,
            keepalive_timeout = 5000,
            keepalive_pool = 10,
        })
    else
        -- Manual redirect handling with revalidation at each hop
        local current_url = target_url
        local current_parsed = parsed
        local redirect_count = 0

        while true do
            res, req_err = httpc:request_uri(current_url, {
                method = "POST",
                body = req_body,
                headers = {
                    ["Content-Type"] = content_type,
                    ["User-Agent"] = "WebhookForwarder/1.0",
                    ["Host"] = current_parsed.host,
                },
                ssl_verify = true,
                keepalive_timeout = 5000,
                keepalive_pool = 10,
            })

            if not res then
                break
            end

            -- Check if this is a redirect
            local status = res.status
            if status == 301 or status == 302 or status == 303 or status == 307 or status == 308 then
                redirect_count = redirect_count + 1
                if redirect_count > MAX_REDIRECTS then
                    ngx.log(ngx.WARN, "redirect limit exceeded for: ", target_url)
                    ngx.status = 502
                    ngx.header["Content-Type"] = "application/json"
                    ngx.say('{"error":"too many redirects"}')
                    return ngx.exit(502)
                end

                local location = res.headers["Location"]
                if not location then
                    break  -- No location header, treat as final response
                end

                -- Handle relative redirects
                if not location:match("^https?://") then
                    location = current_parsed.scheme .. "://" .. current_parsed.host .. location
                end

                -- CRITICAL: Revalidate the redirect destination
                local redirect_parsed, redirect_err = validate_url(location)
                if not redirect_parsed then
                    ngx.log(ngx.WARN, "SSRF protection blocked redirect to: ", location,
                            " from: ", current_url, " reason: ", redirect_err)
                    ngx.status = 403
                    ngx.header["Content-Type"] = "application/json"
                    ngx.say('{"error":"redirect to forbidden destination","detail":"' .. redirect_err .. '"}')
                    return ngx.exit(403)
                end

                current_url = location
                current_parsed = redirect_parsed
                ngx.log(ngx.INFO, "following validated redirect to: ", location)

                -- For 303, change method to GET
                if status == 303 then
                    req_body = nil
                end
            else
                break  -- Not a redirect, we have our final response
            end
        end
    end

    if not res then
        ngx.log(ngx.ERR, "request to ", target_url, " failed: ", req_err)
        ngx.status = 502
        ngx.header["Content-Type"] = "application/json"
        ngx.say('{"error":"upstream request failed","detail":"' .. (req_err or "unknown") .. '"}')
        return ngx.exit(502)
    end

    -- Limit response body size
    local body = res.body or ""
    if #body > MAX_RESPONSE_BODY_SIZE then
        ngx.log(ngx.WARN, "response body too large from: ", target_url, " size: ", #body)
        ngx.status = 502
        ngx.header["Content-Type"] = "application/json"
        ngx.say('{"error":"upstream response too large"}')
        return ngx.exit(502)
    end

    -- Forward the response back to the caller
    ngx.status = res.status

    -- Forward safe response headers
    local safe_headers = {
        "Content-Type",
        "X-Request-Id",
    }
    for _, header_name in ipairs(safe_headers) do
        if res.headers[header_name] then
            ngx.header[header_name] = res.headers[header_name]
        end
    end

    ngx.print(body)

    ngx.log(ngx.INFO, "webhook forwarded successfully to: ", parsed.host,
            " status: ", res.status, " body_size: ", #body)
end

